import React, { useState } from 'react';

const App = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [scanInput, setScanInput] = useState('AAPL,MSFT,GOOGL');
  const [scanResults, setScanResults] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const url = isSignUp ? 'http://localhost:5001/api/auth/register' : 'http://localhost:5001/api/auth/login';
      const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isSignUp ? { email, password, name } : { email, password }) });
      const data = await res.json();
      if (data.token) {
        localStorage.setItem('token', data.token);
        setIsLoggedIn(true);
        setPage('dashboard');
      } else {
        alert('Error: ' + (data.error || 'Failed'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const handleScan = async (e) => {
    e.preventDefault();
    const tickers = scanInput.split(',').map(t => t.trim());
    const token = localStorage.getItem('token');
    try {
      const res = await fetch('http://localhost:5001/api/scan', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token }, body: JSON.stringify({ tickers }) });
      const data = await res.json();
      setScanResults(data.results || []);
    } catch (err) {
      alert('Error: ' + err.message);
    }
  };

  if (page === 'landing') return <div style={{ padding: '2rem', textAlign: 'center', background: '#0f172a', color: 'white', minHeight: '100vh' }}><h1>Bailey's Gauge</h1><p>Professional Stock Scanner</p><button onClick={() => { setIsSignUp(false); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', marginRight: '1rem' }}>Sign In</button><button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>Sign Up</button></div>;

  if (page === 'auth') return <div style={{ padding: '2rem', textAlign: 'center', background: '#0f172a', color: 'white', minHeight: '100vh' }}><div style={{ maxWidth: '400px', margin: '0 auto', background: 'rgba(30,41,59,0.8)', padding: '2rem', borderRadius: '12px' }}><h2>{isSignUp ? 'Sign Up' : 'Sign In'}</h2><form onSubmit={handleAuth}>{isSignUp && <input type="text" placeholder="Name" value={name} onChange={(e) => setName(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none' }} required />}<input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none' }} required /><input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem', borderRadius: '8px', border: 'none' }} required /><button type="submit" style={{ width: '100%', padding: '0.75rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>{loading ? 'Loading...' : (isSignUp ? 'Sign Up' : 'Sign In')}</button></form><p style={{ marginTop: '1rem' }}>{isSignUp ? 'Have account?' : 'No account?'} <button onClick={() => setIsSignUp(!isSignUp)} style={{ background: 'none', border: 'none', color: '#10b981', cursor: 'pointer' }}>{isSignUp ? 'Sign In' : 'Sign Up'}</button></p><button onClick={() => setPage('landing')} style={{ width: '100%', marginTop: '1rem', padding: '0.75rem', background: 'transparent', color: '#94a3b8', border: '1px solid rgba(148,163,184,0.2)', borderRadius: '8px', cursor: 'pointer' }}>Back</button></div></div>;

  if (page === 'dashboard' && isLoggedIn) return <div style={{ padding: '2rem', background: '#0f172a', color: 'white', minHeight: '100vh' }}><div style={{ marginBottom: '2rem', display: 'flex', justifyContent: 'space-between' }}><h1>Bailey's Gauge</h1><button onClick={() => { localStorage.removeItem('token'); setIsLoggedIn(false); setPage('landing'); }} style={{ padding: '0.5rem 1rem', background: '#ef4444', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Logout</button></div><form onSubmit={handleScan} style={{ marginBottom: '2rem', display: 'flex', gap: '1rem' }}><input type="text" value={scanInput} onChange={(e) => setScanInput(e.target.value)} placeholder="AAPL,MSFT,GOOGL" style={{ flex: 1, padding: '0.75rem', borderRadius: '8px', border: 'none' }} /><button type="submit" style={{ padding: '0.75rem 2rem', background: '#10b981', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>Scan</button></form>{scanResults.length > 0 && <table style={{ width: '100%', borderCollapse: 'collapse' }}><thead><tr style={{ borderBottom: '1px solid #333' }}><th style={{ padding: '1rem', textAlign: 'left' }}>Ticker</th><th style={{ padding: '1rem', textAlign: 'left' }}>Price</th><th style={{ padding: '1rem', textAlign: 'left' }}>Change</th><th style={{ padding: '1rem', textAlign: 'left' }}>RSI</th></tr></thead><tbody>{scanResults.map((s, i) => <tr key={i} style={{ borderBottom: '1px solid #333' }}><td style={{ padding: '1rem' }}>{s.ticker}</td><td style={{ padding: '1rem' }}>${s.price}</td><td style={{ padding: '1rem', color: s.change > 0 ? '#10b981' : '#ef4444' }}>{s.change}%</td><td style={{ padding: '1rem' }}>{s.rsi}</td></tr>)}</tbody></table>}</div>;

  return null;
};

export default App;
